                      <p className="text-white font-bold text-lg">
                        {Math.floor(route.estimatedDuration / 60)}h{" "}
                        {route.estimatedDuration % 60}m
                      </p>
                    </div>
                    <div className="bg-slate-900/50 rounded-lg p-3">
                      <p className="text-slate-500">Distance</p>
                      <p className="text-white font-bold text-lg">
