                    >
                      <ExternalLink className="mr-2 h-4 w-4" />
                      Navigate
                    </Button>
                  </div>

                  {currentStop.delivery?.notes && (
                    <div className="bg-slate-900/50 rounded-lg p-3">
                      <div className="flex items-center gap-2 text-slate-400 text-sm mb-1">
