        await html5QrCode.start(
          { facingMode: "environment" },
          config,
          (decodedText) => {
            setScannedBarcode(decodedText);
            setIsScanning(false);
            html5QrCode
              .stop()
              .catch((err) => console.error("Stop failed", err));
          },
          (errorMessage) => {
            // Scanning...
          },
        );
      } catch (err) {
        console.error("Camera access failed:", err);
