import { useState, useRef, useCallback } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  Upload,
  FileSpreadsheet,
  Search,
  AlertCircle,
  CheckCircle,
  ChevronDown,
  AlertTriangle,
  Ban,
  Check,
  Download,
  Printer,
  Eye,
  Plus,
} from "lucide-react";
import { Button } from "./ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "./ui/card";
import { Input } from "./ui/input";
import { Label } from "./ui/label";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "./ui/alert-dialog";
import * as XLSX from "xlsx";
import JsBarcode from "jsbarcode";

interface DeliveryOrder {
  id: number;
  rxNumber: string;
  pharmacyId: number;
  batchId: number | null;
  fillDate: string | null;
  deliveryIdentifier: string | null;
  deliveryStatus: string;
  routeId: number | null;
  addressText: string;
  streetAddress: string | null;
  city: string | null;
  state: string | null;
  zipCode: string | null;
  lat: number | null;
  lng: number | null;
  customerName: string | null;
  customerPhone: string | null;
  notes: string | null;
  priority: string | null;
  uploadCount: number;
  lastSeenAt: string;
  scannedAt: string | null;
  createdAt: string;
}

interface OrderManagementProps {
  batchId?: number | null;
  pharmacyId?: number | null;
  onBatchCreated?: (batchId: number) => void;
  onBatchSelected?: (batchId: number | null) => void;
}

const STATUS_COLORS: Record<string, { bg: string; text: string; icon: React.ReactNode }> = {
  IMPORTED: {
    bg: "bg-yellow-500/20",
    text: "text-yellow-400",
    icon: <AlertCircle className="h-4 w-4 text-yellow-400" />,
  },
  ROUTE_ELIGIBLE: {
    bg: "bg-green-500/20",
    text: "text-green-400",
    icon: <CheckCircle className="h-4 w-4 text-green-400" />,
  },
  ROUTED: {
    bg: "bg-blue-500/20",
    text: "text-blue-400",
    icon: <CheckCircle className="h-4 w-4 text-blue-400" />,
  },
  DELIVERED: {
    bg: "bg-purple-500/20",
    text: "text-purple-400",
    icon: <CheckCircle className="h-4 w-4 text-purple-400" />,
  },
};

export default function OrderManagement({
  batchId,
  pharmacyId,
  onBatchCreated,
  onBatchSelected,
}: OrderManagementProps) {
  const [selectedBatchId, setSelectedBatchId] = useState<number | null>(
    batchId || null,
  );
  const queryClient = useQueryClient();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState<string>("");
  const [uploadResult, setUploadResult] = useState<{
    newOrderCount: number;
    updatedOrderCount: number;
    totalRows: number;
    skippedCount: number;
    skippedReasons: string[];
  } | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [scanMessage, setScanMessage] = useState<{ text: string; type: "success" | "warning" | "error" } | null>(null);
  const barcodeInputRef = useRef<HTMLInputElement>(null);
  const [confirmAction, setConfirmAction] = useState<{
    type: "complete" | "cancel";
    batchId?: number;
  } | null>(null);
  const [showAddOrderDialog, setShowAddOrderDialog] = useState(false);
  const [newOrderRx, setNewOrderRx] = useState("");
  const [newOrderAddress, setNewOrderAddress] = useState("");
  const [newOrderCustomerName, setNewOrderCustomerName] = useState("");
  const [newOrderCustomerPhone, setNewOrderCustomerPhone] = useState("");
  const [newOrderNotes, setNewOrderNotes] = useState("");

  const { data: batches = [] } = useQuery<any[]>({
    queryKey: ["/api/batches"],
  });

  const activeBatchId = selectedBatchId || batchId;

  const { data: orders = [] } = useQuery<DeliveryOrder[]>({
    queryKey: activeBatchId
      ? [`/api/delivery-orders/by-batch/${activeBatchId}`]
      : ["/api/delivery-orders"],
    enabled: true,
  });

  const handleBatchChange = (newBatchId: number | null) => {
    setSelectedBatchId(newBatchId);
    if (onBatchSelected) {
      onBatchSelected(newBatchId);
    }
  };

  const uploadMutation = useMutation({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("name", `Upload ${new Date().toLocaleString()}`);

      const response = await fetch("/api/batches/upload", {
        method: "POST",
        body: formData,
        credentials: "include",
      });

      if (!response.ok) {
        throw new Error("Upload failed");
      }

      return response.json();
    },
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ["/api/batches"] });
      if (activeBatchId) {
        queryClient.invalidateQueries({
          queryKey: [`/api/delivery-orders/by-batch/${activeBatchId}`],
        });
      }
      queryClient.invalidateQueries({ queryKey: ["/api/delivery-orders"] });
      if (onBatchCreated && data.batch) {
        onBatchCreated(data.batch.id);
      }
      if (data.batch) {
        setSelectedBatchId(data.batch.id);
      }
      setUploadResult({
        newOrderCount: data.newOrderCount || 0,
        updatedOrderCount: data.updatedOrderCount || 0,
        totalRows: data.totalRows || 0,
        skippedCount: data.skippedCount || 0,
        skippedReasons: data.skippedReasons || [],
      });
      setIsUploading(false);
      setUploadProgress("");
    },
    onError: (error) => {
      console.error("Upload error:", error);
      setIsUploading(false);
      setUploadProgress("Upload failed. Please try again.");
    },
  });

  const scanBarcodeMutation = useMutation({
    mutationFn: async (barcode: string) => {
      const response = await fetch("/api/delivery-orders/scan-barcode", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ barcode }),
        credentials: "include",
      });
      if (!response.ok) {
        const err = await response.json().catch(() => ({ error: "Scan failed" }));
        throw new Error(err.error || "Scan failed");
      }
      return response.json();
    },
    onSuccess: (data) => {
      if (activeBatchId) {
        queryClient.invalidateQueries({
          queryKey: [`/api/delivery-orders/by-batch/${activeBatchId}`],
        });
      }
      queryClient.invalidateQueries({ queryKey: ["/api/delivery-orders"] });

      if (data.alreadyProcessed) {
        setScanMessage({ text: data.message || "Already scanned", type: "warning" });
      } else {
        setScanMessage({ text: data.message || "Scanned successfully - marked ROUTE_ELIGIBLE", type: "success" });
      }
      setTimeout(() => setScanMessage(null), 4000);
    },
    onError: (error: Error) => {
      const rxMatch = error.message.match(/RX: (.+)/);
      const scannedRx = rxMatch ? rxMatch[1] : "";
      setNewOrderRx(scannedRx);
      setShowAddOrderDialog(true);
      setScanMessage({ text: error.message, type: "error" });
      setTimeout(() => setScanMessage(null), 6000);
    },
  });

  const resetNewOrderForm = () => {
    setNewOrderRx("");
    setNewOrderAddress("");
    setNewOrderCustomerName("");
    setNewOrderCustomerPhone("");
    setNewOrderNotes("");
  };

  const createOrderMutation = useMutation({
    mutationFn: async (data: { rxNumber: string; addressText: string; customerName: string; customerPhone: string; notes: string }) => {
      const response = await fetch("/api/delivery-orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
        credentials: "include",
      });
      if (!response.ok) {
        const err = await response.json().catch(() => ({ error: "Failed to create order" }));
        throw new Error(err.error || "Failed to create order");
      }
      return response.json();
    },
    onSuccess: (data) => {
      if (activeBatchId) {
        queryClient.invalidateQueries({ queryKey: [`/api/delivery-orders/by-batch/${activeBatchId}`] });
      }
      queryClient.invalidateQueries({ queryKey: ["/api/delivery-orders"] });
      setShowAddOrderDialog(false);
      resetNewOrderForm();
      const msg = data.geocodeWarning
        ? `Order created for RX ${data.rxNumber} - ${data.geocodeWarning}`
        : `Order created for RX ${data.rxNumber} - marked as ROUTE_ELIGIBLE`;
      setScanMessage({ text: msg, type: data.geocodeWarning ? "warning" : "success" });
      setTimeout(() => setScanMessage(null), 6000);
    },
    onError: (error: Error) => {
      setScanMessage({ text: error.message, type: "error" });
      setTimeout(() => setScanMessage(null), 4000);
    },
  });

  const updateStatusMutation = useMutation({
    mutationFn: async ({ orderId, status }: { orderId: number; status: string }) => {
      const response = await fetch(`/api/delivery-orders/${orderId}/status`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status }),
        credentials: "include",
      });
      if (!response.ok) throw new Error("Failed to update status");
      return response.json();
    },
    onSuccess: () => {
      if (activeBatchId) {
        queryClient.invalidateQueries({
          queryKey: [`/api/delivery-orders/by-batch/${activeBatchId}`],
        });
      }
      queryClient.invalidateQueries({ queryKey: ["/api/delivery-orders"] });
    },
  });

  const markScanMutation = useMutation({
    mutationFn: async (orderId: number) => {
      const response = await fetch(`/api/delivery-orders/${orderId}/scan`, {
        method: "POST",
        credentials: "include",
      });
      if (!response.ok) throw new Error("Failed to mark as scanned");
      return response.json();
    },
    onSuccess: () => {
      if (activeBatchId) {
        queryClient.invalidateQueries({
          queryKey: [`/api/delivery-orders/by-batch/${activeBatchId}`],
        });
      }
      queryClient.invalidateQueries({ queryKey: ["/api/delivery-orders"] });
    },
  });

  const setBatchStatusMutation = useMutation({
    mutationFn: async ({
      batchId,
      status,
    }: {
      batchId: number;
      status: string;
    }) => {
      const response = await fetch(`/api/batches/${batchId}/status`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status }),
        credentials: "include",
      });
      if (!response.ok) throw new Error("Failed to update batch status");
      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/batches"] });
      if (activeBatchId) {
        queryClient.invalidateQueries({
          queryKey: [`/api/delivery-orders/by-batch/${activeBatchId}`],
        });
      }
    },
  });

  const handleFileUpload = useCallback(
    async (file: File) => {
      const fileName = file.name.toLowerCase();

      if (fileName.endsWith(".xlsx") || fileName.endsWith(".xls")) {
        setIsUploading(true);
        setUploadProgress("Processing Excel file...");
        setUploadResult(null);

        const reader = new FileReader();
        reader.onload = async (e) => {
          try {
            const data = new Uint8Array(e.target?.result as ArrayBuffer);
            const workbook = XLSX.read(data, { type: "array" });
            const sheetName = workbook.SheetNames[0];
            const worksheet = workbook.Sheets[sheetName];
            const jsonData = XLSX.utils.sheet_to_csv(worksheet);

            const blob = new Blob([jsonData], { type: "text/csv" });
            const csvFile = new File(
              [blob],
              file.name.replace(/\.xlsx?$/, ".csv"),
              { type: "text/csv" },
            );

            uploadMutation.mutate(csvFile);
          } catch (error) {
            console.error("Excel parsing error:", error);
            setIsUploading(false);
            setUploadProgress("Failed to parse Excel file");
          }
        };
        reader.readAsArrayBuffer(file);
      } else if (fileName.endsWith(".csv")) {
        setIsUploading(true);
        setUploadProgress("Uploading CSV file...");
        setUploadResult(null);
        uploadMutation.mutate(file);
      } else {
        setUploadProgress(
          "Please upload a CSV or Excel file (.csv, .xlsx, .xls)",
        );
      }
    },
    [uploadMutation],
  );

  const canPrintLabel = (order: DeliveryOrder) => {
    return order.deliveryIdentifier && (order.deliveryStatus === 'ROUTE_ELIGIBLE' || order.deliveryStatus === 'ROUTED' || order.deliveryStatus === 'DELIVERED');
  };

  const printDeliveryLabel = (
    order: DeliveryOrder,
    pharmacyName: string = "RX Delivery Pharmacy",
